    Manifest.permission.ACCESS_FINE_LOCATION,
    Manifest.permission.ACCESS_BACKGROUND_LOCATION
))

questions.solution:
val bgLocationLauncher = registerForActivityResult(
    ActivityResultContracts.RequestPermission()
) { bgGranted ->
    if (bgGranted) {
        startLocationTracking()
    } else {
        startForegroundOnlyTracking()
    }
}

val fgLocationLauncher = registerForActivityResult(
    ActivityResultContracts.RequestPermission()
) { fgGranted ->
    if (fgGranted) {
        // Foreground granted вҖ” NOW request background separately
        bgLocationLauncher.launch(Manifest.permission.ACCESS_BACKGROUND_LOCATION)
    } else {
        showLocationDeniedUI()
    }
}

// Step 1: request foreground location first
fgLocationLauncher.launch(Manifest.permission.ACCESS_FINE_LOCATION)
